#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
using NP std;
il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
	return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
int n,i=0,j=0;
signed main(void)
{
	n=read();
	wh(n>j)
	{
		++i,j+=i;
	}
	if(i%2==1)
	{
		write(j-n+1);
		pc('/');
		write(i+n-j);
	}
	else
	{
		write(i+n-j);
		pc('/');
		write(j-n+1);
	}
	return false;
}
